class Solution {
    public static long[] solve(long[] nums) {
        int n = nums.length;
        long[] ans = new long[2 * n];

        // First half: ans[i] = nums[i]
        for (int i = 0; i < n; i++) {
            ans[i] = nums[i];
        }

        // Second half: ans[i + n] = nums[n - i - 1]
        for (int i = 0; i < n; i++) {
            // The index in the reversed part is i + n
            // The corresponding index in nums is n - 1 - i
            ans[i + n] = nums[n - 1 - i];
        }

        return ans;
    }
}
